mapper.select:
WITH filtered_oce AS ( SELECT * FROM oce o
AND o.number LIKE CONCAT('%', #{q.number}, '%') AND o.data LIKE CONCAT('%', #{q.data}, '%') AND o.time >= #{q.startDate} AND o.time <= #{q.endDate} AND o.examine = #{q.examine} AND o.nucleus = #{q.nucleus}
), bill_sum AS ( SELECT pid, SUM(money) AS sum_money FROM oce_bill WHERE pid IN (SELECT id FROM filtered_oce) GROUP BY pid ) SELECT o.id, f.`name` AS frame, s.`name` AS supplier, o.`time`, o.`number`, o.`total`, o.`actual`, o.`money`, IFNULL(b.sum_money, 0) AS writeOffAmount, a.`name` AS account, p.`name` AS people, o.examine, o.nucleus, u.`name` AS `user`, o.`data` FROM filtered_oce o LEFT JOIN bill_sum b ON b.pid = o.id LEFT JOIN frame f ON f.id = o.frame LEFT JOIN supplier s ON s.id = o.supplier LEFT JOIN people p ON p.id = o.people LEFT JOIN account a ON a.id = o.account LEFT JOIN `user` u ON u.id = o.`user`
AND s.id = #{q.supplier} AND a.id = #{q.account} AND p.id = #{q.people} AND u.id = #{q.user}
ORDER BY o.time DESC, o.id DESC

mapper.update:
UPDATE oce
SET frame=#{frame}, supplier=#{supplier}, time=#{time}, number=#{number},
    total=#{total}, actual=#{actual}, money=#{money}, account=#{account},
    people=#{people}, file=#{file}, data=#{data}, more=#{more}
WHERE id=#{id}

UPDATE oce
SET examine = #{examine}
WHERE id IN

    #{id}
